# OEIS sequence: A344820

def A344820(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k*(n**(j-1) if j&1 else -n**(j-1))*(1+n**a if (a:=m-j+1)&1 else 1-n**a)
        j = m+1
    return c//(n+1) # _Chai Wah Wu_, May 11 2026

